import{_ as e,o as t,c as s,e as i}from"./app-cb4c34a4.js";const o={},a=i("<p>This is the second alpha of v3. This release fixes problems with schedule signaling when AdoJobStore is in use. This release removes the last bits of Quartz&#39;s usage of thread local storage and thus makes async-based operations a lot safer.</p><p><strong>FIXES</strong></p><ul><li>fix scheduler signaling not working with AdoJobStore due to thread local storage</li><li>thread local state removed altogether</li><li>quartz.serializer.type was required even though non-serializing RAMJobStore was in use</li><li>JSON serialization incorrectly called serialization callbacks</li></ul><p><strong>BREAKING CHANGES</strong></p><ul><li>IStatefulJob was removed, been obsolete since 2.x</li><li>ISemaphore interface now passes Guid requestorId that defines lock owner instead of implicit thread name</li></ul><p><strong>KNOWN ISSUES</strong></p><ul><li>Issues with time zone ids between Windows and Linux, they use different ids for the same zone</li><li>No remoting support</li><li>Documentation lacking</li></ul><p>Check NuGet for pre-release packages.</p>",8),l=[a];function r(n,c){return t(),s("div",null,l)}const u=e(o,[["render",r],["__file","2016-08-24-quartznet-3.0-alpha2-released.html.vue"]]);export{u as default};
